#[async_trait]
impl<R: OAuthProviderProjectionRepository> OAuthProviderEventHandler for OAuthProviderProjector<R> {

    async fn on_created(&self, event: OAuthProviderCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = OAuthProviderProjection::new(
            event.id,
            event.provider_name,
            event.display_name,
            event.client_id,
            event.client_secret,
            event.redirect_uri,
            event.scopes,
            event.authorization_url,
            event.token_url,
            event.user_info_url,
            event.is_active,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: OAuthProviderUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.provider_name = event.provider_name;
            projection.display_name = event.display_name;
            projection.client_id = event.client_id;
            projection.client_secret = event.client_secret;
            projection.redirect_uri = event.redirect_uri;
            projection.scopes = event.scopes;
            projection.authorization_url = event.authorization_url;
            projection.token_url = event.token_url;
            projection.user_info_url = event.user_info_url;
            projection.is_active = event.is_active;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: OAuthProviderDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

